messages.content:
This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define i32 @not_d_allSignBits(i32 %cond, i32 %tval, i32 %fval) {
  %bitmask = ashr i32 %cond, 31
  %a1 = and i32 %tval, %bitmask
  %or = or i32 %bitmask, %fval
  %a2 = xor i32 %or, -1
  %sel = or i32 %a1, %a2
  ret i32 %sel
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i32 @not_d_allSignBits(i32 %cond, i32 %tval, i32 %fval) {
  %1 = icmp slt i32 %cond, 0
  %2 = xor i32 %fval, -1
  %sel = select i1 %1, i32 %tval, i32 %2
  ret i32 %sel
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp:InstCombinerImpl::visitTrunc to implement the missed optimization:
```cpp
    Value *Zero = Constant::getNullValue(SrcTy);

    Value *X;
    const APInt *C1;
    Constant *C2;
    if (match(Src, m_OneUse(m_Shr(m_Shl(m_Power2(C1), m_Value(X)),
                                  m_ImmConstant(C2))))) {
      // trunc ((C1 << X) >> C2) to i1 --> X == (C2-cttz(C1)), where C1 is pow2
      Constant *Log2C1 = ConstantInt::get(SrcTy, C1->exactLogBase2());
      Constant *CmpC = ConstantExpr::getSub(C2, Log2C1);
      return new ICmpInst(ICmpInst::ICMP_EQ, X, CmpC);
    }

    Constant *C;
    if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
      // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0
      Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
      Value *MaskC = Builder.CreateShl(One, C);
      Value *And = Builder.CreateAnd(X, MaskC);
      return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
    }
    if (match(Src, m_OneUse(m_c_Or(m_LShr(m_Value(X), m_ImmConstant(C)),
                                   m_Deferred(X))))) {
      // trunc (or (lshr X, C), X) to i1 --> icmp ne (and X, C'), 0
      Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
      Value *MaskC = Builder.CreateShl(One, C);
```

